1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type Step = { items: Item[] };
13	type Scenario = { steps: Step[] };
14	
15	export function processScenario(scenario: unknown): unknown {
16	  const { steps } = scenario as Scenario;
17	  const items = steps[0].items;
18	  const basePremium = items.reduce(
19	    (sum, item) => sum + (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0),
20	    0,
21	  );
22	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
23	}
